class Solution:
    def alphabetBoardPath(self, target: str) -> str:
        board = ["abcde", "fghij", "klmno", "pqrst", "uvwxy", "z"]
        loc = {}
        for i, row in enumerate(board):
            for j, c in enumerate(row):
                loc[c] = (i, j)

        res = []
        r, c = 0, 0
        for char in target:
            i, j = loc[char]
            if i < r:
                res.append('U' * (r - i))
            if i > r:
                res.append('D' * (i - r))
            if j < c:
                res.append('L' * (c - j))
            if j > c:
                res.append('R' * (j - c))
            res.append('!')
            r, c = i, j

        return ''.join(res)
